INSERT INTO erp.policies (id, title, category, version, status, effective_date, content) VALUES
  ('90000001-0001-4000-8000-000000000001', 'GDPR Data Handling Policy', 'privacy', '1.2', 'active', '2026-01-01', 'All customer PII must be encrypted at rest and in transit. Data retention limited to 36 months. Right to erasure must be fulfilled within 30 days.'),
  ('90000001-0001-4000-8000-000000000002', 'CCPA Consumer Rights Policy', 'privacy', '1.0', 'active', '2026-01-01', 'California consumers have the right to know, delete, and opt-out of sale of personal information. Annual disclosure required.'),
  ('90000001-0001-4000-8000-000000000003', 'Return & Refund Policy', 'operational', '2.1', 'active', '2026-01-15', '30-day return window for undamaged items. Full refund within 5 business days. Custom orders non-refundable.'),
  ('90000001-0001-4000-8000-000000000004', 'Intellectual Property Policy', 'legal', '1.0', 'active', '2026-01-01', 'All AI-generated art is owned by VividWalls. Customer receives non-exclusive personal use license. Commercial licenses available for B2B.'),
  ('90000001-0001-4000-8000-000000000005', 'Marketing Ethics Policy', 'marketing', '1.1', 'active', '2026-01-15', 'No misleading claims. All testimonials must be verified. AI art labeled as AI-generated. CAN-SPAM compliance for all emails.'),
  ('90000001-0001-4000-8000-000000000006', 'PCI DSS Compliance Policy', 'security', '1.0', 'active', '2026-01-01', 'No storage of full card numbers. Tokenized payment processing via Stripe. Quarterly vulnerability scans required.'),
  ('90000001-0001-4000-8000-000000000007', 'Age Verification Policy', 'legal', '1.0', 'active', '2026-01-01', 'No sales to minors under 13. Age gate on custom portrait orders. Parental consent required for under-18 custom work.'),
  ('90000001-0001-4000-8000-000000000008', 'Accessibility Compliance (ADA/WCAG)', 'accessibility', '1.0', 'draft', '2026-03-01', 'Website must meet WCAG 2.1 AA standards. Alt text for all product images. Keyboard navigation support required.')
INSERT INTO erp.violations (id, policy_id, severity, status, description, reported_by, resolution_notes, resolved_at) VALUES
  ('aa000001-0001-4000-8000-000000000001', '90000001-0001-4000-8000-000000000001', 'critical', 'open', 'GDPR consent form missing from checkout flow — EU customers can complete purchases without explicit data processing consent', 'compliance_agent', NULL, NULL),
  ('aa000001-0001-4000-8000-000000000002', '90000001-0001-4000-8000-000000000005', 'medium', 'open', 'Marketing email sent without unsubscribe link to 12 contacts in February batch', 'marketing_agent', NULL, NULL),
  ('aa000001-0001-4000-8000-000000000003', '90000001-0001-4000-8000-000000000003', 'low', 'resolved', 'Return processed after 30-day window for order #1024 — customer service override not documented', 'coo_agent', 'Exception approved by COO. Process updated to require documentation for all overrides.', '2026-02-15'),
  ('aa000001-0001-4000-8000-000000000004', '90000001-0001-4000-8000-000000000006', 'medium', 'resolved', 'Quarterly PCI vulnerability scan was 5 days overdue', 'cto_agent', 'Scan completed. No vulnerabilities found. Calendar reminder set for future scans.', '2026-02-10'),
  ('aa000001-0001-4000-8000-000000000005', '90000001-0001-4000-8000-000000000004', 'low', 'resolved', 'Product image used in Pinterest ad was not tagged as AI-generated', 'legal_agent', 'Image updated with AI disclosure tag. All ad creatives reviewed and updated.', '2026-02-18')
