INSERT INTO erp.compliance_guardrails (id, name, category, description, rule_expression, severity, active) VALUES
  ('ff000001-0001-4000-8000-000000000001', 'Marketing Spend Cap', 'financial', 'Monthly marketing spend must not exceed $2,000 without CFO approval', 'marketing_monthly_spend <= 2000', 'warning', true),
  ('ff000001-0001-4000-8000-000000000002', 'Order Fulfillment SLA', 'operational', 'Orders must ship within 3 business days of payment', 'order_ship_time_days <= 3', 'critical', true),
  ('ff000001-0001-4000-8000-000000000003', 'GDPR Data Retention', 'legal', 'Customer PII must be purged after 36 months of inactivity', 'customer_inactive_months <= 36', 'critical', true),
  ('ff000001-0001-4000-8000-000000000004', 'Sales Tax Collection', 'tax', 'Sales tax must be collected for all US orders based on destination state', 'us_order_has_tax == true', 'critical', true),
