INSERT INTO erp.reports (id, name, type, query, parameters, schedule, status, last_run_at) VALUES
  ('ab000001-0001-4000-8000-000000000001', 'Monthly Revenue Report', 'financial', 'SELECT date_trunc(''month'', created_at) as month, SUM(total) as revenue FROM erp.orders WHERE status NOT IN (''cancelled'') GROUP BY 1 ORDER BY 1', '{}', '0 0 1 * *', 'active', '2026-02-01'),
  ('ab000001-0001-4000-8000-000000000002', 'Customer Acquisition Report', 'operational', 'SELECT lifecycle_stage, COUNT(*) as count FROM erp.contacts GROUP BY 1', '{}', '0 9 * * 1', 'active', '2026-02-24'),
  ('ab000001-0001-4000-8000-000000000003', 'Product Performance Report', 'kpi', 'SELECT p.name, p.category, p.stock_qty, COUNT(o.id) as order_count FROM erp.products p LEFT JOIN erp.orders o ON o.line_items::text LIKE ''%'' || p.sku || ''%'' GROUP BY 1,2,3 ORDER BY 4 DESC', '{}', '0 9 * * *', 'active', '2026-02-27'),
  ('ab000001-0001-4000-8000-000000000004', 'Campaign ROI Report', 'financial', 'SELECT c.name, c.budget, SUM(cm.value) FILTER (WHERE cm.metric_type=''revenue'') as revenue FROM erp.campaigns c LEFT JOIN erp.campaign_metrics cm ON cm.campaign_id=c.id GROUP BY 1,2', '{}', '0 0 * * 1', 'active', '2026-02-24')
